import { createClient, streams } from "@trigger.dev/sdk";
import { agentTask } from "./src/trigger/agent";

const TRIAL_ID = "ai_agent_with_tool_and_streaming__ZbC7ga3";

async function main() {
  // Create a Trigger.dev client
  const client = createClient({
    accessToken: process.env.TRIGGER_SECRET_KEY!,
  });

  // Trigger the agent task with a city (e.g., "Paris")
  const run = await agentTask.trigger(client, {
    city: "Paris",
  });

  console.log(`Task triggered with run ID: ${run.id}`);

  // Subscribe to the ai-output stream
  const stream = streams.read(run.id, "ai-output");

  // Print each chunk as it arrives
  for await (const chunk of stream) {
    console.log(chunk);
  }

  // Print the run ID at the end
  console.log(`Run ID: ${run.id}`);
}

main().catch((error) => {
  console.error("Error:", error);
  process.exit(1);
});

